query:
UPDATE crowdfunding_projects p
SET raisedAmount = (
  SELECT COALESCE(SUM(amount), 0)
  FROM crowdfunding_participations cp
  WHERE cp.projectId = p.id AND cp.paymentStatus = 'COMPLETED'
);

